474	      const target = event.target as HTMLElement | null;
475	      if (target) {
476	        const tag = target.tagName;
477	        if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return;
478	        if (target.isContentEditable) return;
479	      }
480	      const fromMode = modeForHotkey(event.key);
481	      if (fromMode) {
482	        event.preventDefault();
483	        handleModeChange(fromMode);
484	        return;
485	      }
486	      if (event.key === '?') {
487	        event.preventDefault();
488	        setCheatsheetOpen((v) => !v);
489	        return;
490	      }
491	      if ((event.key === 'k' || event.key === 'K') && (event.metaKey || event.ctrlKey)) {
492	        event.preventDefault();
493	        setPaletteOpen((v) => !v);
494	        return;
495	      }
496	      // Tab cycling — Ctrl/⌘+Tab forward, Ctrl/⌘+Shift+Tab back.
497	      if (event.key === 'Tab' && (event.metaKey || event.ctrlKey)) {
498	        event.preventDefault();
499	        setTabsState((s) => cycleActive(s, event.shiftKey ? 'backward' : 'forward'));
500	        return;
501	      }
502	      // Close active tab — Ctrl/⌘+W.
503	      if ((event.key === 'w' || event.key === 'W') && (event.metaKey || event.ctrlKey)) {
504	        event.preventDefault();
505	        setTabsState((s) => (s.activeId ? closeTab(s, s.activeId) : s));
506	        return;
507	      }
508	      // Undo/Redo — Ctrl/⌘+Z / Ctrl/⌘+Shift+Z.
509	      if ((event.key === 'z' || event.key === 'Z') && (event.metaKey || event.ctrlKey)) {
510	        event.preventDefault();
511	        void handleUndoRedo(event.shiftKey ? false : true);
512	        return;
513	      }
514	      // V opens VV (Visibility/Graphics) dialog
515	      if (event.key === 'v' || event.key === 'V') {
516	        if (!event.metaKey && !event.ctrlKey && !event.altKey) {
517	          event.preventDefault();
518	          openVVDialog();
519	          return;
520	        }
521	      }
522	      // Ortho snap hold on Shift
523	      if (event.shiftKey) setOrthoSnapHold(true);
524	      // Tool hotkeys — match the spec'd letters from TOOL_REGISTRY.
525	      const upper = event.key.length === 1 ? event.key.toUpperCase() : event.key;
526	      const hotkeyLabel = event.shiftKey ? `Shift+${upper}` : upper;
527	      const tool = (Object.values(toolRegistry) as { id: ToolId; hotkey: string }[]).find(
528	        (tool) => tool.hotkey === hotkeyLabel,
