532	        if (legacy) {
533	          event.preventDefault();
534	          setPlanTool(legacy);
535	        }
536	      }
537	    };
538	    const onKeyUp = (event: globalThis.KeyboardEvent): void => {
539	      if (!event.shiftKey) setOrthoSnapHold(false);
540	    };
