1	import {
2	  type CSSProperties,
3	  type JSX,
4	  type KeyboardEvent,
5	  type ReactNode,
6	  useCallback,
7	  useId,
8	  useState,
9	} from 'react';
10	import { useTranslation } from 'react-i18next';
11	import { Icons, ICON_SIZE } from '@bim-ai/ui';
12	import type { LensMode } from '@bim-ai/core';
13	import type { CollaborationConflictQueueV1 } from '../lib/collaborationConflictQueue';
14	import { LensDropdown } from './LensDropdown';
15	import { DriftBadge } from './DriftBadge';
16	
17	/**
18	 * StatusBar — spec §17.
19	 *
20	 * 28 px tall surface bar, bottom-of-shell. Shows clusters from left to
21	 * right: active level, current tool, snap mode group, grid toggle, model
22	 * coordinates, undo depth, ws connection, save state.
23	 *
24	 * - Coordinates use `aria-live="polite"` so screen-readers can announce
25	 *   changes without interrupting.
26	 * - The save-state pill uses `aria-live="polite"` too.
27	 * - Errors / red-alert states (offline, save failed) use
28	 *   `aria-live="assertive"`.
29	 * - Every cluster has a tooltip via `title` and a hotkey hint where the
30	 *   spec specifies one (`F3` for snap cycle, `F7` for grid).
31	 */
32	
33	export type StatusSaveState = 'saved' | 'saving' | 'unsynced' | 'error';
34	export type StatusWsState = 'connected' | 'reconnecting' | 'offline';
35	
36	export interface StatusBarProps {
37	  level: { id: string; label: string };
38	  levels?: { id: string; label: string }[];
39	  onLevelChange?: (id: string) => void;
40	  toolLabel?: string | null;
41	  /** Snap mode group; toggling individual snaps lives here. */
42	  snapModes?: { id: string; label: string; on: boolean }[];
43	  onSnapToggle?: (id: string) => void;
44	  gridOn?: boolean;
45	  onGridToggle?: () => void;
46	  /** Live cursor model coords, in mm; null when off-canvas. */
47	  cursorMm?: { xMm: number; yMm: number } | null;
48	  /** Undo depth; clicking the cluster invokes undo / redo. */
49	  undoDepth?: number;
50	  onUndo?: () => void;
51	  onRedo?: () => void;
52	  wsState?: StatusWsState;
53	  saveState?: StatusSaveState;
54	  conflictQueue?: CollaborationConflictQueueV1 | null;
55	  onClearConflict?: () => void;
56	  /** CHR-V3-03 slot 5 — lens discipline filter. */
57	  lensMode?: LensMode;
58	  onLensChange?: (lens: LensMode) => void;
59	  /** CHR-V3-03 slot 6 — federation drift count; hidden when 0. */
60	  driftCount?: number;
61	  onDriftClick?: () => void;
62	}
63	
64	export function StatusBar({
65	  level,
66	  levels = [],
67	  onLevelChange,
68	  toolLabel,
69	  snapModes = [],
70	  onSnapToggle,
71	  gridOn = true,
72	  onGridToggle,
73	  cursorMm,
74	  undoDepth,
75	  onUndo,
76	  onRedo,
77	  wsState = 'connected',
78	  saveState = 'saved',
79	  conflictQueue,
80	  onClearConflict,
81	  lensMode = 'all',
82	  onLensChange,
83	  driftCount = 0,
84	  onDriftClick,
85	}: StatusBarProps): JSX.Element {
86	  return (
87	    <div
88	      data-testid="status-bar"
89	      role="contentinfo"
90	      style={statusStyle}
91	      className="relative flex w-full items-center gap-3 border-t border-border bg-surface px-4 text-xs"
92	    >
93	      <LevelCluster level={level} levels={levels} onLevelChange={onLevelChange} />
94	      <Divider />
95	      <ToolCluster toolLabel={toolLabel ?? null} />
96	      <Divider />
97	      <SnapCluster snapModes={snapModes} onSnapToggle={onSnapToggle} />
98	      <Divider />
99	      <GridCluster gridOn={gridOn} onGridToggle={onGridToggle} />
100	      <Divider />
101	      <CoordCluster cursorMm={cursorMm ?? null} />
102	      <div className="ml-auto flex items-center gap-3">
103	        {conflictQueue ? (
104	          <>
105	            <ConflictSlot queue={conflictQueue} onClear={onClearConflict} />
106	            <Divider />
107	          </>
108	        ) : null}
109	        <UndoCluster depth={undoDepth ?? 0} onUndo={onUndo} onRedo={onRedo} />
110	        <Divider />
111	        <WsCluster state={wsState} />
112	        <Divider />
113	        <SaveCluster state={saveState} />
114	        <Divider />
115	        {/* Slot 5 — lens dropdown (CHR-V3-03 keystone, A8 antidote) */}
116	        <LensDropdown currentLens={lensMode} onLensChange={onLensChange ?? (() => {})} />
117	        {/* Slot 6 — drift badge; hidden when driftCount = 0 */}
118	        {driftCount > 0 ? (
119	          <>
120	            <Divider />
121	            <DriftBadge driftCount={driftCount} onClick={onDriftClick ?? (() => {})} />
122	          </>
123	        ) : null}
124	      </div>
125	    </div>
126	  );
127	}
128	
129	const statusStyle: CSSProperties = {
130	  height: 'var(--shell-statusbar-height)',
131	  minHeight: 'var(--shell-statusbar-height)',
132	};
133	
134	function Divider(): JSX.Element {
135	  return <span aria-hidden="true" className="inline-block h-3 w-px bg-border" />;
136	}
137	
138	function ConflictSlot({
139	  queue,
140	  onClear,
141	}: {
142	  queue: CollaborationConflictQueueV1;
143	  onClear?: () => void;
144	}): JSX.Element {
145	  const { t } = useTranslation();
146	  const [expanded, setExpanded] = useState(false);
147	  const retryLabels: Record<string, string> = {
148	    safe: t('statusbar.conflict.safeRetry'),
149	    blocked: t('statusbar.conflict.blocked'),
150	    requires_manual_edit: t('statusbar.conflict.manualEdit'),
151	  };
152	  const retryLabel = retryLabels[queue.retryAdvice] ?? queue.retryAdvice;
153	  return (
154	    <div className="relative flex items-center">
155	      <button
156	        type="button"
157	        aria-expanded={expanded}
158	        data-testid="conflict-pill"
159	        onClick={() => setExpanded((v) => !v)}
160	        className="flex items-center gap-1 rounded-sm px-1.5 py-0.5 font-medium text-amber-700 hover:bg-amber-50 dark:text-amber-300 dark:hover:bg-amber-950/30"
161	        title={t('statusbar.conflict.pill')}
162	      >
163	        <Icons.advisorWarning size={ICON_SIZE.chrome} aria-hidden="true" />
164	        <span>{t('statusbar.conflict.label')}</span>
165	        <span className="rounded bg-amber-100 px-1 py-px text-[9px] dark:bg-amber-900/40">
166	          {retryLabel}
167	        </span>
168	      </button>
169	      {expanded ? (
170	        <div
171	          data-testid="collaboration-conflict-queue-readout"
172	          role="dialog"
173	          aria-label={t('statusbar.conflict.dialogAriaLabel')}
174	          className="absolute bottom-full right-0 z-50 mb-1 w-96 rounded border border-amber-500/40 bg-surface px-3 py-2 text-[10px] shadow-elev-2"
175	        >
176	          <div className="flex items-center justify-between">
177	            <span className="font-semibold text-amber-800 dark:text-amber-300">
178	              {t('statusbar.conflict.heading')}
179	            </span>
180	            <button
181	              type="button"
182	              aria-label={t('statusbar.conflict.dismissAriaLabel')}
183	              data-testid="conflict-dismiss"
184	              onClick={() => {
185	                setExpanded(false);
186	                onClear?.();
187	              }}
188	              className="rounded-sm px-1 py-0.5 text-muted hover:bg-surface-strong"
189	            >
190	              ✕
191	            </button>
192	          </div>
193	          <p className="mt-1 text-foreground">{queue.inspectionReadout}</p>
194	          {queue.inspectionReadoutSecondary ? (
195	            <p className="mt-0.5 text-muted">{queue.inspectionReadoutSecondary}</p>
196	          ) : null}
197	          {queue.mergePreflightReadout ? (
198	            <p className="mt-0.5 text-muted">{queue.mergePreflightReadout}</p>
199	          ) : null}
200	          <ul className="mt-1 list-disc space-y-0.5 ps-4 text-muted">
201	            <li>
202	              Retry advice: <code className="font-mono text-[9px]">{queue.retryAdvice}</code>
203	              {queue.reason ? (
204	                <>
205	                  {' · '}reason <code className="font-mono text-[9px]">{queue.reason}</code>
206	                </>
207	              ) : null}
208	            </li>
209	            {queue.rows.length > 0 ? (
210	              <li>
211	                {queue.rows.length} blocking row(s) · rules{' '}
212	                <code className="text-[9px]">{queue.rows.map((r) => r.ruleId).join(', ')}</code>
213	              </li>
214	            ) : null}
215	            {queue.firstBlockingCommandStep1Based !== null ? (
216	              <li>
217	                Blocking command step {queue.firstBlockingCommandStep1Based}
218	                {queue.blockingCommandType ? ` (${queue.blockingCommandType})` : ''}
219	              </li>
220	            ) : null}
221	          </ul>
222	        </div>
223	      ) : null}
224	    </div>
225	  );
226	}
227	
228	function LevelCluster({
229	  level,
230	  levels,
231	  onLevelChange,
232	}: {
233	  level: { id: string; label: string };
234	  levels: { id: string; label: string }[];
235	  onLevelChange?: (id: string) => void;
236	}): JSX.Element {
237	  const { t } = useTranslation();
238	  const [open, setOpen] = useState(false);
239	  const popoverId = useId();
240	  const close = useCallback(() => setOpen(false), []);
241	  const handleKey = useCallback(
242	    (event: KeyboardEvent<HTMLDivElement>) => {
243	      if (event.key === 'PageDown' || event.key === 'PageUp') {
244	        if (!levels.length) return;
245	        const idx = levels.findIndex((l) => l.id === level.id);
246	        if (idx < 0) return;
247	        const delta = event.key === 'PageDown' ? 1 : -1;
248	        const next = levels[(idx + delta + levels.length) % levels.length];
249	        event.preventDefault();
