        const entry = flatEntries[activeIndex];
        if (entry) invoke(entry);
      }
    },
    [activeIndex, flatEntries, invoke, onClose],
  );

  if (!isOpen) return null;

  let globalIdx = 0;

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-label="Command palette"
      data-testid="cmd-palette-v3"
      style={{
        position: 'fixed',
        inset: 0,
        zIndex: 60,
        display: 'flex',
        alignItems: 'flex-start',
        justifyContent: 'center',
        paddingTop: 96,
        background: 'rgba(0,0,0,0.4)',
      }}
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        style={{
          width: 480,
          maxHeight: '60vh',
          display: 'flex',
          flexDirection: 'column',
          borderRadius: 'var(--radius-card, 4px)',
          border: '1px solid var(--color-border)',
          background: 'var(--color-surface)',
          boxShadow: 'var(--shadow-elev-3)',
          overflow: 'hidden',
        }}
        onKeyDown={handleKeyDown}
      >
        {/* Search input */}
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 8,
            padding: '8px 12px',
            borderBottom: '1px solid var(--color-border)',
          }}
        >
          <input
            ref={inputRef}
            type="text"
            value={query}
            onChange={(e) => {
              setQuery(e.target.value);
              setActiveIndex(0);
            }}
            placeholder="Type a command…"
            aria-label="Command palette search"
            aria-autocomplete="list"
            style={{
              flex: 1,
              background: 'transparent',
              border: 'none',
              outline: 'none',
              fontSize: 'var(--text-base, 14px)',
              color: 'var(--color-foreground)',
            }}
          />
          <kbd
            style={{
              padding: '2px 6px',
              borderRadius: 'var(--radius-card, 4px)',
              border: '1px solid var(--color-border)',
              background: 'var(--color-background)',
              fontFamily: 'monospace',
              fontSize: 11,
              color: 'var(--color-muted)',
            }}
          >
            Esc
          </kbd>
        </div>

        {/* Result list */}
        <div
          ref={listRef}
          role="listbox"
          aria-label="Commands"
          style={{ flex: 1, overflowY: 'auto', padding: '4px 0' }}
        >
          {flatEntries.length === 0 ? (
            <div
              style={{
                padding: '12px 16px',
                fontSize: 'var(--text-sm, 12px)',
                color: 'var(--color-muted)',
              }}
            >
              No matches
            </div>
          ) : (
            sections.map(({ category, items }) => (
              <div key={category}>
                <div
                  style={{
                    padding: '4px 12px 2px',
                    fontSize: 'var(--text-2xs, 10px)',
                    letterSpacing: '0.06em',
                    textTransform: 'uppercase',
                    color: 'var(--color-muted)',
                  }}
                >
                  {CATEGORY_LABELS[category]}
                </div>
                {items.map((entry) => {
                  const idx = globalIdx++;
                  const isActive = idx === activeIndex;
                  return (
                    <button
                      key={entry.id}
                      type="button"
                      role="option"
                      aria-selected={isActive}
                      data-testid={`palette-entry-${entry.id}`}
                      onClick={() => invoke(entry)}
                      onMouseEnter={() => setActiveIndex(idx)}
                      style={{
                        display: 'flex',
                        width: '100%',
                        alignItems: 'center',
                        justifyContent: 'space-between',
                        padding: '6px 12px',
                        fontSize: 'var(--text-sm, 12px)',
                        color: 'var(--color-foreground)',
                        background: isActive ? 'var(--color-accent-soft)' : 'transparent',
                        border: 'none',
                        cursor: 'pointer',
                        textAlign: 'left',
                      }}
                    >
                      <span>{entry.label}</span>
                      {entry.shortcut ? (
                        <kbd
                          style={{
                            padding: '1px 5px',
                            borderRadius: 'var(--radius-card, 4px)',
                            border: '1px solid var(--color-border)',
                            background: 'var(--color-background)',
                            fontFamily: 'monospace',
                            fontSize: 10,
                            color: 'var(--color-muted)',
                            flexShrink: 0,
                          }}
                        >
                          {entry.shortcut}
                        </kbd>
                      ) : null}
                    </button>
                  );
                })}
              </div>
            ))
          )}
        </div>

        {/* Footer hint */}
        <div
          style={{
            padding: '6px 12px',
            borderTop: '1px solid var(--color-border)',
            background: 'var(--color-surface-muted)',
            fontSize: 'var(--text-2xs, 10px)',
            color: 'var(--color-muted)',
          }}
        >
          ↑↓ navigate · Enter invoke · Esc close
        </div>
      </div>
    </div>
  );
}

